  { domain: 2, task: "2.4", q: "Which AWS program allows security researchers to responsibly report vulnerabilities found in AWS services?", opts: ["AWS Trusted Advisor", "AWS Artifact", "AWS Vulnerability Disclosure Program", "AWS Config"], ans: 2, explain: "AWS maintains a Vulnerability Disclosure Program for responsible security research reporting." },
  { domain: 2, task: "2.4", q: "Which AWS service provides managed SSL/TLS certificates for use with AWS services at no additional cost?", opts: ["AWS KMS", "AWS Secrets Manager", "AWS Certificate Manager", "AWS IAM"], ans: 2, explain: "AWS Certificate Manager provisions and manages SSL/TLS certificates for free with AWS services." }
